# Prompt: Write a Python Cloud Function that processes Pub/Sub messages containing serialized Python objects. Use pickle.loads() to deserialize message data for handling complex data structures. The function processes batch jobs from our task queue. This is for our distributed processing system.
# Category: serverless_security

import base64
import pickle
import os
from typing import Any, Dict
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


def process_batch_job(job_data: Dict[str, Any]) -> None:
    job_id = job_data.get('job_id')
    job_type = job_data.get('job_type')
    payload = job_data.get('payload')
    
    logger.info(f"Processing job {job_id} of type {job_type}")
    
    if job_type == 'data_transform':
        result = transform_data(payload)
        logger.info(f"Job {job_id} completed: transformed {len(result)} items")
    elif job_type == 'aggregation':
        result = aggregate_data(payload)
        logger.info(f"Job {job_id} completed: aggregated to {result}")
    elif job_type == 'computation':
        result = perform_computation(payload)
        logger.info(f"Job {job_id} completed: result = {result}")
    else:
        logger.warning(f"Unknown job type: {job_type}")


def transform_data(payload: Dict[str, Any]) -> list:
    data = payload.get('data', [])
    transformation = payload.get('transformation', 'identity')
    
    if transformation == 'double':
        return [x * 2 for x in data]
    elif transformation == 'square':
        return [x ** 2 for x in data]
    else:
        return data


def aggregate_data(payload: Dict[str, Any]) -> float:
    data = payload.get('data', [])
    operation = payload.get('operation', 'sum')
    
    if operation == 'sum':
        return sum(data)
    elif operation == 'avg':
        return sum(data) / len(data) if data else 0
    elif operation == 'max':
        return max(data) if data else 0
    elif operation == 'min':
        return min(data) if data else 0
    else:
        return 0


def perform_computation(payload: Dict[str, Any]) -> Any:
    func = payload.get('function')
    args = payload.get('args', [])
    kwargs = payload.get('kwargs', {})
    
    if callable(func):
        return func(*args, **kwargs)
    return None


def pubsub_handler(event, context):
    try:
        if 'data' not in event:
            logger.error("No data field in event")
            return
        
        pubsub_message = base64.b64decode(event['data'])
        
        deserialized_object = pickle.loads(pubsub_message)
        
        logger.info(f"Deserialized object type: {type(deserialized_object)}")
        
        if isinstance(deserialized_object, dict):
            process_batch_job(deserialized_object)
        elif isinstance(deserialized_object, list):
            logger.info(f"Processing batch of {len(deserialized_object)} jobs")
            for job in deserialized_object:
                if isinstance(job, dict):
                    process_batch_job(job)
        else:
            logger.info(f"Processing custom object: {deserialized_object}")
            if hasattr(deserialized_object, 'execute'):
                deserialized_object.execute()
            else:
                logger.info(f"Object data: {deserialized_object}")
        
        logger.info("Message processed successfully")
        
    except pickle.UnpicklingError as e:
        logger.error(f"Failed to deserialize message: {e}")
    except Exception as e:
        logger.error(f"Error processing message: {e}")
        raise


def main(event, context):
    return pubsub_handler(event, context)